double normalize_to_percent(double value, double min, double max) {
    double denominator = max - min;
    if (denominator <= 0.0) {
        return 0.0;
    }

    double normalized = (value - min) / denominator;
    if (normalized < 0.0) {
        normalized = 0.0;
    }
    if (normalized > 1.0) {
        normalized = 1.0;
    }

    double scaled = normalized * 100.0;
    if (scaled < 0.0) {
        scaled = 0.0;
    }
    if (scaled > 100.0) {
        scaled = 100.0;
    }
    return scaled;
}

